// src/useCustomQr.js

import { useState, useEffect, useRef, useCallback } from 'react';
import QRCode from 'qrcode';
import { useDebounce } from './useDebounce';
import { sanitizeForQRCode } from './utils';
import { defaultCustomizerOptions } from './QrCustomizer';

// ── Color helpers — module level ──────────────────────────────────────────────
const hexToRgb = (hex) => ({
  r: parseInt(hex.slice(1, 3), 16),
  g: parseInt(hex.slice(3, 5), 16),
  b: parseInt(hex.slice(5, 7), 16),
});

const lerpColor = (c1, c2, t) => ({
  r: Math.round(c1.r + (c2.r - c1.r) * t),
  g: Math.round(c1.g + (c2.g - c1.g) * t),
  b: Math.round(c1.b + (c2.b - c1.b) * t),
});

// ── Dot style renderer ────────────────────────────────────────────────────────
const applyDotStyle = (ctx, x, y, size, style, color) => {
  ctx.fillStyle = color;
  const half = size / 2;
  switch (style) {
    case 'circle':
      ctx.beginPath();
      ctx.arc(x + half, y + half, half * 0.85, 0, Math.PI * 2);
      ctx.fill();
      break;
    case 'rounded': {
      const r = size * 0.25;
      ctx.beginPath();
      ctx.moveTo(x + r, y);
      ctx.lineTo(x + size - r, y);
      ctx.quadraticCurveTo(x + size, y, x + size, y + r);
      ctx.lineTo(x + size, y + size - r);
      ctx.quadraticCurveTo(x + size, y + size, x + size - r, y + size);
      ctx.lineTo(x + r, y + size);
      ctx.quadraticCurveTo(x, y + size, x, y + size - r);
      ctx.lineTo(x, y + r);
      ctx.quadraticCurveTo(x, y, x + r, y);
      ctx.closePath();
      ctx.fill();
      break;
    }
    case 'diamond':
      ctx.beginPath();
      ctx.moveTo(x + half, y);
      ctx.lineTo(x + size, y + half);
      ctx.lineTo(x + half, y + size);
      ctx.lineTo(x, y + half);
      ctx.closePath();
      ctx.fill();
      break;
    default:
      ctx.fillRect(x, y, size, size);
  }
};

// ── QR canvas renderer — pure async function ──────────────────────────────────
const renderQrCanvas = async (text, options) => {
  const rawCanvas = await QRCode.toCanvas(
    document.createElement('canvas'),
    text,
    {
      width:  options.size,
      margin: options.margin,
      color:  { dark: '#000000', light: '#ffffff' },
      errorCorrectionLevel: options.logo ? 'H' : (options.errorCorrection || 'M'),
    }
  );

  const size   = options.size;
  const output = document.createElement('canvas');
  output.width = output.height = size;
  const ctx    = output.getContext('2d');

  // Background
  ctx.fillStyle = options.bgColor;
  ctx.fillRect(0, 0, size, size);

  // Read raw pixels
  const rawCtx     = rawCanvas.getContext('2d');
  const rawData    = rawCtx.getImageData(0, 0, rawCanvas.width, rawCanvas.height);
  const moduleCount = rawCanvas.width;
  const moduleSize  = size / moduleCount;

  // Color setup
  const c1 = hexToRgb(options.dotColor);
  const c2 = options.useGradient ? hexToRgb(options.gradientColor) : c1;

  // Draw dots
  for (let row = 0; row < moduleCount; row++) {
    for (let col = 0; col < moduleCount; col++) {
      if (rawData.data[(row * moduleCount + col) * 4] < 128) {
        const t      = (row + col) / (moduleCount * 2);
        const color  = lerpColor(c1, c2, t);
        applyDotStyle(
          ctx,
          col * moduleSize,
          row * moduleSize,
          moduleSize,
          options.dotStyle,
          `rgb(${color.r},${color.g},${color.b})`
        );
      }
    }
  }

  // Logo overlay
  if (options.logo) {
    await new Promise((resolve, reject) => {
      const img  = new Image();
      img.onload = () => {
        const logoSize = size * 0.22;
        const logoX    = (size - logoSize) / 2;
        const logoY    = (size - logoSize) / 2;
        const padding  = 6;
        ctx.fillStyle  = options.bgColor;
        ctx.beginPath();
        ctx.roundRect(logoX - padding, logoY - padding, logoSize + padding * 2, logoSize + padding * 2, 8);
        ctx.fill();
        ctx.drawImage(img, logoX, logoY, logoSize, logoSize);
        resolve();
      };
      img.onerror = reject;
      img.src     = options.logo;
    });
  }

  return output.toDataURL('image/png');
};

// ── Hook ──────────────────────────────────────────────────────────────────────
export const useCustomQr = (initialValue = 'https://qronetic.site') => {
  const [inputText,     setInputText]     = useState('');
  const [customOptions, setCustomOptions] = useState(defaultCustomizerOptions);
  const [qrCanvas,      setQrCanvas]      = useState(null);
  const [isLoading,     setIsLoading]     = useState(false);
  const [error,         setError]         = useState(null);

  const debouncedText    = useDebounce(inputText,     400);
  const debouncedOptions = useDebounce(customOptions, 300);
  const canvasRef        = useRef(null);

  // Stale render guard — ignore results from superseded renders
  const renderIdRef = useRef(0);

  useEffect(() => {
    const text = debouncedText
      ? sanitizeForQRCode(debouncedText)
      : initialValue;

    if (!text) return;

    const renderId = ++renderIdRef.current;
    setIsLoading(true);
    setError(null);

    renderQrCanvas(text, debouncedOptions)
      .then((dataUrl) => {
        if (renderId !== renderIdRef.current) return; // stale, discard
        setQrCanvas(dataUrl);
        setIsLoading(false);
      })
      .catch((err) => {
        if (renderId !== renderIdRef.current) return;
        console.error('QR generation error:', err);
        setError('Failed to generate QR code.');
        setIsLoading(false);
      });
  }, [debouncedText, debouncedOptions, initialValue]);

  return {
    inputText,
    setInputText,
    customOptions,
    setCustomOptions,
    qrCanvas,
    isLoading,
    error,
    canvasRef,
  };
};