// src/Button.js

import React, { memo } from 'react';

const ArrowIcon = () => (
  <svg
    xmlns="http://www.w3.org/2000/svg"
    className="h-4 w-4"
    fill="none"
    viewBox="0 0 24 24"
    stroke="currentColor"
    strokeWidth="2.5"
    aria-hidden="true"
  >
    <path strokeLinecap="round" strokeLinejoin="round" d="M3 12h14" />
    <path strokeLinecap="round" strokeLinejoin="round" d="M13 6l6 6-6 6" />
  </svg>
);

const Button = memo(({ onClick, children, type = 'button', disabled = false, ariaLabel }) => {
  const label = ariaLabel || (typeof children === 'string' ? children : undefined);

  return (
    <button
      type={type}
      onClick={onClick}
      disabled={disabled}
      aria-label={label}
      className="group relative w-auto cursor-pointer overflow-hidden rounded-full border border-purple-500/30 bg-white px-5 py-2 text-center font-medium text-gray-900 shadow-sm transition-all duration-300 hover:shadow-purple-500/20 hover:shadow-md disabled:opacity-50 disabled:cursor-not-allowed dark:border-purple-500/20 dark:bg-[#1a1a2e] dark:text-white dark:hover:border-purple-500/40 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-purple-500 focus-visible:ring-offset-2"
    >
      {/* Default state */}
      <div className="flex items-center gap-3">
        <div className="h-4 w-4 rounded-full bg-purple-600 transition-all duration-300 group-hover:scale-[100.8] dark:bg-purple-500" />
        <span className="inline-block transition-all duration-300 group-hover:translate-x-12 group-hover:opacity-0">
          {children}
        </span>
      </div>

      {/* Hover reveal state */}
      <div className="absolute top-0 z-10 flex h-full w-full translate-x-12 items-center justify-center gap-3 rounded-full bg-purple-600 text-white opacity-0 transition-all duration-300 group-hover:-translate-x-5 group-hover:opacity-100">
        <div className="flex items-center gap-3 whitespace-nowrap">
          <span className="leading-none font-medium">{children}</span>
          <ArrowIcon />
        </div>
      </div>
    </button>
  );
});

Button.displayName = 'Button';

export default Button;