// src/QrAiAssistant.js
import React, { useState, useCallback, memo, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

// ── Static configs ────────────────────────────────────────────────────────────
const fadeUp   = { initial: { opacity: 0, y: 12 }, animate: { opacity: 1, y: 0 }, transition: { duration: 0.3 } };
const msgEnter = { initial: { opacity: 0, y: 8, scale: 0.98 }, animate: { opacity: 1, y: 0, scale: 1 }, transition: { duration: 0.25 } };

const SUGGESTIONS = [
  { emoji: "📶", text: "WiFi QR for my coffee shop called Brewed Awakenings, password is morning2026" },
  { emoji: "💼", text: "Business card QR for Sarah Chen, UX Designer at Pixel Labs, sarah@pixellabs.io" },
  { emoji: "🔗", text: "URL QR for my portfolio at sarahdesigns.com" },
  { emoji: "📅", text: "Event QR for my birthday party, July 15th 2026 at Central Park, NYC" },
  { emoji: "💬", text: "SMS QR to text +1 555 0123 with message 'I want to book a table'" },
  { emoji: "₿",  text: "Bitcoin payment QR for wallet 1A1zP1eP5QGefi2DMPTfTL5SLmv7Divf" },
];

// ── Message bubble ────────────────────────────────────────────────────────────
const MessageBubble = memo(({ role, content, isLoading }) => {
  const isUser = role === 'user';
  return (
    <motion.div {...msgEnter} className={"flex " + (isUser ? "justify-end" : "justify-start")}>
      {!isUser && (
        <div className="w-7 h-7 rounded-full bg-gradient-to-br from-purple-500 to-indigo-600 flex items-center justify-center flex-shrink-0 mr-2 mt-0.5">
          <span className="text-white text-xs font-bold">AI</span>
        </div>
      )}
      <div className={"max-w-[85%] px-4 py-3 rounded-2xl text-sm leading-relaxed " + (isUser
        ? "bg-purple-600 text-white rounded-tr-sm"
        : "bg-white dark:bg-[#1a1a2e] border border-gray-100 dark:border-purple-500/20 text-gray-700 dark:text-gray-300 rounded-tl-sm shadow-sm"
      )}>
        {isLoading ? (
          <div className="flex items-center gap-1.5">
            <div className="w-1.5 h-1.5 rounded-full bg-purple-400" style={{ animation: 'dotBounce 1.2s ease-in-out 0s infinite' }} />
            <div className="w-1.5 h-1.5 rounded-full bg-purple-400" style={{ animation: 'dotBounce 1.2s ease-in-out 0.2s infinite' }} />
            <div className="w-1.5 h-1.5 rounded-full bg-purple-400" style={{ animation: 'dotBounce 1.2s ease-in-out 0.4s infinite' }} />
          </div>
        ) : content}
      </div>
    </motion.div>
  );
});
MessageBubble.displayName = 'MessageBubble';

// ── Result card ───────────────────────────────────────────────────────────────
const ResultCard = memo(({ result, onUse }) => (
  <motion.div
    {...fadeUp}
    className="bg-purple-50 dark:bg-purple-900/20 border border-purple-200 dark:border-purple-500/20 rounded-2xl p-4 space-y-3"
  >
    <div className="flex items-start gap-3">
      <div className="w-8 h-8 rounded-xl bg-purple-600 flex items-center justify-center flex-shrink-0">
        <span className="text-white text-sm">⬡</span>
      </div>
      <div className="flex-1 min-w-0">
        <p className="text-xs font-bold text-purple-600 dark:text-purple-400 uppercase tracking-wide mb-1">
          QR Ready — {result.type.toUpperCase()}
        </p>
        <p className="text-sm text-gray-700 dark:text-gray-300">{result.summary}</p>
      </div>
    </div>

    <div className="bg-white dark:bg-[#0f0f1a] rounded-xl p-3 border border-gray-100 dark:border-purple-500/10">
      <p className="text-xs text-gray-400 dark:text-gray-600 font-medium mb-1 uppercase tracking-wide">QR Content</p>
      <p className="text-xs font-mono text-gray-600 dark:text-gray-400 break-all line-clamp-3">
        {result.qrString}
      </p>
    </div>

    <button
      onClick={() => onUse(result)}
      className="w-full py-2.5 rounded-xl bg-purple-600 hover:bg-purple-700 text-white text-sm font-semibold transition-colors duration-200"
    >
      ✦ Generate This QR Code →
    </button>
  </motion.div>
));
ResultCard.displayName = 'ResultCard';

// ── Suggestion chip ───────────────────────────────────────────────────────────
const SuggestionChip = memo(({ emoji, text, onClick }) => (
  <button
    onClick={() => onClick(text)}
    className="flex items-center gap-2 px-3 py-2 rounded-xl bg-white dark:bg-[#1a1a2e] border border-gray-200 dark:border-purple-500/20 text-xs text-gray-600 dark:text-gray-400 hover:border-purple-400 dark:hover:border-purple-500/50 hover:text-purple-600 dark:hover:text-purple-400 transition-colors duration-200 text-left"
  >
    <span className="flex-shrink-0">{emoji}</span>
    <span className="truncate">{text}</span>
  </button>
));
SuggestionChip.displayName = 'SuggestionChip';

// ── Main component ────────────────────────────────────────────────────────────
const QrAiAssistant = memo(({ onGenerate }) => {
  const [messages,   setMessages]   = useState([]);
  const [input,      setInput]      = useState('');
  const [isLoading,  setIsLoading]  = useState(false);
  const [lastResult, setLastResult] = useState(null);
  const [error,      setError]      = useState('');
  const [showSuggs,  setShowSuggs]  = useState(true);
  const bottomRef  = useRef(null);
  const inputRef   = useRef(null);

  // Scroll to bottom on new message
  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading]);

  const sendMessage = useCallback(async (textInput) => {
    const userText = String(textInput || input).trim();
    if (!userText || isLoading) return;

    setInput('');
    setError('');
    setShowSuggs(false);
    setLastResult(null);

    setMessages(prev => [...prev, { role: 'user', content: userText }]);
    setIsLoading(true);

    try {
      // --- Call your backend instead of Gemini directly ---
      const res = await fetch("http://localhost:5000/api/gemini", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ prompt: userText }),
      });

      if (!res.ok) {
        throw new Error("Server error");
      }

      const data = await res.json();

      // Gemini API returns choices[0].content.text for text
      const rawText = data?.candidates?.[0]?.content?.[0]?.text || "I couldn't understand that. Try: WiFi QR for MyNetwork, password 12345678";

      let parsed = null;
      try {
        parsed = JSON.parse(rawText);
      } catch (err) {
        parsed = {
          type: "text",
          fields: {},
          qrString: rawText,
          summary: rawText
        };
      }

      setLastResult(parsed);
      setMessages(prev => [...prev, { role: 'assistant', content: parsed.summary }]);
    } catch (err) {
      console.error(err);
      setError("Something went wrong. Please try again.");
      setMessages(prev => [...prev, { role: 'assistant', content: "Something went wrong. Please try again." }]);
    }

    setIsLoading(false);
  }, [input, isLoading]);

  const handleKeyDown = useCallback((e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  }, [sendMessage]);

  const handleUse = useCallback((result) => {
    if (onGenerate) {
      onGenerate(result.qrString, result.type, result.fields);
    }
  }, [onGenerate]);

  const handleSuggestion = useCallback((text) => {
    setInput(text);
    inputRef.current?.focus();
  }, []);

  const handleReset = useCallback(() => {
    setMessages([]);
    setInput('');
    setLastResult(null);
    setError('');
    setShowSuggs(true);
  }, []);

  return (
    <div className="flex flex-col h-full min-h-[500px]">

      {/* Header */}
      <div className="flex items-center justify-between mb-4">
        <div>
          <div className="flex items-center gap-2 mb-0.5">
            <div className="w-2 h-2 rounded-full bg-green-500" style={{ animation: 'dotBounce 2s ease-in-out infinite' }} />
            <p className="text-xs font-bold text-purple-600 dark:text-purple-400 uppercase tracking-wide">
              AI Assistant — Online
            </p>
          </div>
          <p className="text-xs text-gray-400 dark:text-gray-600">
            Describe your QR in plain English
          </p>
        </div>
        {messages.length > 0 && (
          <button
            onClick={handleReset}
            className="text-xs text-gray-400 hover:text-red-400 transition-colors duration-200 px-2 py-1 rounded-lg hover:bg-red-50 dark:hover:bg-red-900/20"
          >
            Reset ✕
          </button>
        )}
      </div>

      {/* Chat area */}
      <div className="flex-1 overflow-y-auto no-scrollbar space-y-3 mb-4 min-h-[280px] max-h-[320px]">

        {/* Welcome */}
        {messages.length === 0 && (
          <motion.div {...fadeUp} className="space-y-3">
            <div className="flex justify-start">
              <div className="w-7 h-7 rounded-full bg-gradient-to-br from-purple-500 to-indigo-600 flex items-center justify-center flex-shrink-0 mr-2 mt-0.5">
                <span className="text-white text-xs font-bold">AI</span>
              </div>
              <div className="bg-white dark:bg-[#1a1a2e] border border-gray-100 dark:border-purple-500/20 rounded-2xl rounded-tl-sm px-4 py-3 shadow-sm max-w-[85%]">
                <p className="text-sm text-gray-700 dark:text-gray-300 leading-relaxed">
                  Hey! I'm your QR AI assistant. Tell me what QR code you need in plain English and I'll set it up instantly. ✦
                </p>
              </div>
            </div>

            {/* Suggestions */}
            <AnimatePresence>
              {showSuggs && (
                <motion.div
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  exit={{ opacity: 0 }}
                  className="space-y-2 pl-9"
                >
                  <p className="text-xs text-gray-400 dark:text-gray-600 font-medium">Try one of these:</p>
                  <div className="grid grid-cols-1 gap-1.5">
                    <SuggestionChip emoji={SUGGESTIONS[0].emoji} text={SUGGESTIONS[0].text} onClick={handleSuggestion} />
                    <SuggestionChip emoji={SUGGESTIONS[1].emoji} text={SUGGESTIONS[1].text} onClick={handleSuggestion} />
                    <SuggestionChip emoji={SUGGESTIONS[2].emoji} text={SUGGESTIONS[2].text} onClick={handleSuggestion} />
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
          </motion.div>
        )}

        {/* Messages */}
        {messages.map((msg, i) => (
          <MessageBubble key={i} role={msg.role} content={msg.content} />
        ))}

        {/* Loading */}
        {isLoading && <MessageBubble role="assistant" isLoading={true} />}

        {/* Result card */}
        <AnimatePresence>
          {lastResult && !isLoading && (
            <ResultCard result={lastResult} onUse={handleUse} />
          )}
        </AnimatePresence>

        <div ref={bottomRef} />
      </div>

      {/* Input */}
      <div className="flex gap-2 items-end">
        <div className="flex-1 relative">
          <textarea
            ref={inputRef}
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="e.g. WiFi QR for my café, password latte2026..."
            rows={2}
            disabled={isLoading}
            className="w-full px-4 py-3 pr-12 rounded-2xl border-2 border-gray-200 dark:border-purple-500/20 bg-gray-50 dark:bg-[#0f0f1a] text-gray-900 dark:text-white placeholder-gray-400 dark:placeholder-gray-600 text-sm outline-none focus:border-purple-500 transition-colors duration-200 resize-none disabled:opacity-50"
          />
          <span className="absolute right-3 bottom-3 text-xs text-gray-300 dark:text-gray-700 select-none">↵</span>
        </div>
        <button
          onClick={() => sendMessage()}
          disabled={!input.trim() || isLoading}
          className="flex-shrink-0 w-11 h-11 rounded-2xl bg-purple-600 hover:bg-purple-700 disabled:opacity-40 disabled:cursor-not-allowed text-white flex items-center justify-center transition-colors duration-200"
          aria-label="Send message"
        >
          {isLoading ? (
            <div className="w-4 h-4 rounded-full border-2 border-white/30 border-t-white animate-spin" />
          ) : (
            <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
              <path d="M2 8L14 2L10 8L14 14L2 8Z" fill="currentColor" />
            </svg>
          )}
        </button>
      </div>

      {/* More suggestions below input */}
      {messages.length === 0 && (
        <motion.div {...fadeUp} className="mt-3 grid grid-cols-1 gap-1.5">
          <SuggestionChip emoji={SUGGESTIONS[3].emoji} text={SUGGESTIONS[3].text} onClick={handleSuggestion} />
          <SuggestionChip emoji={SUGGESTIONS[4].emoji} text={SUGGESTIONS[4].text} onClick={handleSuggestion} />
          <SuggestionChip emoji={SUGGESTIONS[5].emoji} text={SUGGESTIONS[5].text} onClick={handleSuggestion} />
        </motion.div>
      )}
    </div>
  );
});

QrAiAssistant.displayName = 'QrAiAssistant';
export default QrAiAssistant;