// src/QrCustomizer.js

import React, { useState, useCallback, memo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { HexColorPicker } from 'react-colorful';

// ── Static animation configs ──────────────────────────────────────────────────
const pickerAnim   = { initial: { opacity: 0, scale: 0.95, y: -6 }, animate: { opacity: 1, scale: 1, y: 0 }, exit: { opacity: 0, scale: 0.95, y: -6 }, transition: { duration: 0.12 } };
const gradientAnim = { initial: { opacity: 0, height: 0 }, animate: { opacity: 1, height: 'auto' }, exit: { opacity: 0, height: 0 }, transition: { duration: 0.15 } };
const customizerAnim = { initial: { opacity: 0, y: 12 }, animate: { opacity: 1, y: 0 }, transition: { duration: 0.3 } };

// ── Default options ───────────────────────────────────────────────────────────
export const defaultCustomizerOptions = {
  dotColor:      '#1a1a2e',
  bgColor:       '#ffffff',
  useGradient:   false,
  gradientColor: '#6c63ff',
  dotStyle:      'square',
  eyeStyle:      'square',
  logo:          null,
  size:          256,
  margin:        2,
  errorCorrection:  'M',
};

// ── Style presets ─────────────────────────────────────────────────────────
const PRESETS = [
  { id: 'classic',   name: 'Classic',   dot: '#1a1a2e', bg: '#ffffff', gradient: false, gc: '#6c63ff', ds: 'square',  es: 'square'  },
  { id: 'midnight',  name: 'Midnight',  dot: '#e2e8f0', bg: '#0f0f1a', gradient: false, gc: '#6c63ff', ds: 'rounded', es: 'rounded' },
  { id: 'ocean',     name: 'Ocean',     dot: '#0891b2', bg: '#f0fdfa', gradient: true,  gc: '#6366f1', ds: 'circle',  es: 'circle'  },
  { id: 'sunset',    name: 'Sunset',    dot: '#f97316', bg: '#fffbeb', gradient: true,  gc: '#ef4444', ds: 'rounded', es: 'rounded' },
  { id: 'forest',    name: 'Forest',    dot: '#15803d', bg: '#f0fdf4', gradient: true,  gc: '#0d9488', ds: 'circle',  es: 'leaf'    },
  { id: 'lavender',  name: 'Lavender',  dot: '#7c3aed', bg: '#faf5ff', gradient: true,  gc: '#c084fc', ds: 'rounded', es: 'rounded' },
  { id: 'neon',      name: 'Neon',      dot: '#22d3ee', bg: '#0a0a14', gradient: true,  gc: '#a855f7', ds: 'circle',  es: 'circle'  },
  { id: 'rose',      name: 'Rosé',      dot: '#e11d48', bg: '#fff1f2', gradient: true,  gc: '#f472b6', ds: 'diamond', es: 'rounded' },
];

// ── Color picker ──────────────────────────────────────────────────────────────
const ColorPicker = memo(({ color, onChange, label }) => {
  const [open, setOpen] = useState(false);
  const toggle          = useCallback(() => setOpen((p) => !p), []);
  const close           = useCallback(() => setOpen(false), []);

  return (
    <div className="relative">
      <label className="block text-xs font-semibold text-gray-600 dark:text-gray-400 uppercase tracking-wide mb-1.5">
        {label}
      </label>
      <button
        type="button"
        onClick={toggle}
        className="flex items-center gap-2 px-3 py-2 rounded-xl border border-gray-200 dark:border-purple-500/20 bg-white dark:bg-[#0f0f1a] w-full hover:border-purple-400/50 transition-colors duration-200"
      >
        <span
          className="w-6 h-6 rounded-lg border border-gray-200 dark:border-gray-700 flex-shrink-0"
          style={{ backgroundColor: color }}
        />
        <span className="text-sm font-mono text-gray-700 dark:text-gray-300">{color}</span>
      </button>

      <AnimatePresence>
        {open && (
          <>
            <div className="fixed inset-0 z-40" onClick={close} />
            <motion.div
              {...pickerAnim}
              className="absolute top-full left-0 mt-2 z-50 bg-white dark:bg-[#1a1a2e] border border-gray-100 dark:border-purple-500/20 rounded-2xl p-4 shadow-xl"
            >
              <HexColorPicker color={color} onChange={onChange} />
              <input
                type="text"
                value={color}
                onChange={(e) => onChange(e.target.value)}
                className="mt-3 w-full px-3 py-1.5 rounded-lg border border-gray-200 dark:border-purple-500/20 bg-gray-50 dark:bg-[#0f0f1a] text-sm font-mono text-gray-700 dark:text-gray-300 outline-none focus:border-purple-500"
              />
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </div>
  );
});
ColorPicker.displayName = 'ColorPicker';

// ── Style option button ───────────────────────────────────────────────────────
const StyleOption = memo(({ value, current, onClick, children, label }) => (
  <button
    type="button"
    onClick={() => onClick(value)}
    title={label}
    className={
      "flex flex-col items-center gap-1.5 p-2 rounded-xl border-2 transition-colors duration-200 " +
      (current === value
        ? "border-purple-500 bg-purple-50 dark:bg-purple-900/20"
        : "border-gray-200 dark:border-gray-700 hover:border-purple-400/50 bg-white dark:bg-[#0f0f1a]")
    }
  >
    {children}
    <span className="text-xs text-gray-500 dark:text-gray-400">{label}</span>
  </button>
));
StyleOption.displayName = 'StyleOption';

// ── SVG previews — static, memo'd ────────────────────────────────────────────
const DotSquare  = memo(() => <svg width="32" height="32" viewBox="0 0 32 32"><rect x="4"  y="4"  width="8" height="8" fill="#6c63ff" /><rect x="14" y="4"  width="8" height="8" fill="#6c63ff" /><rect x="24" y="4"  width="8" height="8" fill="#6c63ff" /><rect x="4"  y="14" width="8" height="8" fill="#6c63ff" /><rect x="24" y="14" width="8" height="8" fill="#6c63ff" /><rect x="4"  y="24" width="8" height="8" fill="#6c63ff" /><rect x="14" y="24" width="8" height="8" fill="#6c63ff" /><rect x="24" y="24" width="8" height="8" fill="#6c63ff" /></svg>);
const DotRounded = memo(() => <svg width="32" height="32" viewBox="0 0 32 32"><rect x="4"  y="4"  width="8" height="8" rx="3" fill="#6c63ff" /><rect x="14" y="4"  width="8" height="8" rx="3" fill="#6c63ff" /><rect x="24" y="4"  width="8" height="8" rx="3" fill="#6c63ff" /><rect x="4"  y="14" width="8" height="8" rx="3" fill="#6c63ff" /><rect x="24" y="14" width="8" height="8" rx="3" fill="#6c63ff" /><rect x="4"  y="24" width="8" height="8" rx="3" fill="#6c63ff" /><rect x="14" y="24" width="8" height="8" rx="3" fill="#6c63ff" /><rect x="24" y="24" width="8" height="8" rx="3" fill="#6c63ff" /></svg>);
const DotCircle  = memo(() => <svg width="32" height="32" viewBox="0 0 32 32"><circle cx="8"  cy="8"  r="4" fill="#6c63ff" /><circle cx="18" cy="8"  r="4" fill="#6c63ff" /><circle cx="28" cy="8"  r="4" fill="#6c63ff" /><circle cx="8"  cy="18" r="4" fill="#6c63ff" /><circle cx="28" cy="18" r="4" fill="#6c63ff" /><circle cx="8"  cy="28" r="4" fill="#6c63ff" /><circle cx="18" cy="28" r="4" fill="#6c63ff" /><circle cx="28" cy="28" r="4" fill="#6c63ff" /></svg>);
const DotDiamond = memo(() => <svg width="32" height="32" viewBox="0 0 32 32"><polygon points="8,4 12,8 8,12 4,8" fill="#6c63ff" /><polygon points="18,4 22,8 18,12 14,8" fill="#6c63ff" /><polygon points="28,4 32,8 28,12 24,8" fill="#6c63ff" /><polygon points="8,14 12,18 8,22 4,18" fill="#6c63ff" /><polygon points="28,14 32,18 28,22 24,18" fill="#6c63ff" /><polygon points="8,24 12,28 8,32 4,28" fill="#6c63ff" /><polygon points="18,24 22,28 18,32 14,28" fill="#6c63ff" /><polygon points="28,24 32,28 28,32 24,28" fill="#6c63ff" /></svg>);
const EyeSquare  = memo(() => <svg width="32" height="32" viewBox="0 0 32 32"><rect x="2" y="2" width="28" height="28" fill="none" stroke="#6c63ff" strokeWidth="3" /><rect x="8" y="8" width="16" height="16" fill="#6c63ff" /></svg>);
const EyeRounded = memo(() => <svg width="32" height="32" viewBox="0 0 32 32"><rect x="2" y="2" width="28" height="28" rx="6" fill="none" stroke="#6c63ff" strokeWidth="3" /><rect x="8" y="8" width="16" height="16" rx="4" fill="#6c63ff" /></svg>);
const EyeCircle  = memo(() => <svg width="32" height="32" viewBox="0 0 32 32"><circle cx="16" cy="16" r="13" fill="none" stroke="#6c63ff" strokeWidth="3" /><circle cx="16" cy="16" r="7" fill="#6c63ff" /></svg>);
const EyeLeaf    = memo(() => <svg width="32" height="32" viewBox="0 0 32 32"><rect x="2" y="2" width="28" height="28" rx="12" ry="2" fill="none" stroke="#6c63ff" strokeWidth="3" /><rect x="8" y="8" width="16" height="16" rx="6" ry="2" fill="#6c63ff" /></svg>);

DotSquare.displayName  = 'DotSquare';
DotRounded.displayName = 'DotRounded';
DotCircle.displayName  = 'DotCircle';
DotDiamond.displayName = 'DotDiamond';
EyeSquare.displayName  = 'EyeSquare';
EyeRounded.displayName = 'EyeRounded';
EyeCircle.displayName  = 'EyeCircle';
EyeLeaf.displayName    = 'EyeLeaf';

// ── Section wrapper ───────────────────────────────────────────────────────────
const Section = memo(({ title, children }) => (
  <div className="space-y-3">
    <p className="text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-widest">
      {title}
    </p>
    {children}
  </div>
));
Section.displayName = 'Section';

// ── Preset card ───────────────────────────────────────────────────────────
const PresetCard = memo(({ preset, isActive, onClick }) => (
  <button
    type="button"
    onClick={() => onClick(preset)}
    title={preset.name}
    className={
      "preset-card flex flex-col items-center gap-1.5 p-2.5 rounded-xl border-2 cursor-pointer " +
      (isActive
        ? "border-purple-500 bg-purple-50 dark:bg-purple-900/20"
        : "border-gray-200 dark:border-gray-700 hover:border-purple-400/50 bg-white dark:bg-[#0f0f1a]")
    }
  >
    <div className="flex gap-0.5">
      <span className="w-4 h-4 rounded-sm" style={{ backgroundColor: preset.dot }} />
      <span className="w-4 h-4 rounded-sm" style={{ backgroundColor: preset.gradient ? preset.gc : preset.dot, opacity: 0.6 }} />
    </div>
    <span className="text-xs font-medium text-gray-600 dark:text-gray-400">{preset.name}</span>
  </button>
));
PresetCard.displayName = 'PresetCard';

// ── Error correction level descriptions ───────────────────────────────────
const EC_LEVELS = [
  { value: 'L', label: 'Low',      desc: '7% recovery',  pct: 25  },
  { value: 'M', label: 'Medium',   desc: '15% recovery', pct: 50  },
  { value: 'Q', label: 'Quartile', desc: '25% recovery', pct: 75  },
  { value: 'H', label: 'High',     desc: '30% recovery', pct: 100 },
];

// ── Toggle switch ─────────────────────────────────────────────────────────────
const Toggle = memo(({ checked, onChange }) => (
  <button
    type="button"
    onClick={onChange}
    className={
      "relative w-11 h-6 rounded-full transition-colors duration-200 " +
      (checked ? "bg-purple-600" : "bg-gray-300 dark:bg-gray-600")
    }
  >
    <span
      className={
        "absolute top-0.5 left-0.5 w-5 h-5 rounded-full bg-white shadow transition-transform duration-200 " +
        (checked ? "translate-x-5" : "translate-x-0")
      }
    />
  </button>
));
Toggle.displayName = 'Toggle';

// ── Main QrCustomizer ─────────────────────────────────────────────────────────
const QrCustomizer = memo(({ options, onChange }) => {
  const [logoPreview, setLogoPreview] = useState(null);
  const [activePreset, setActivePreset] = useState(null);

  const update = useCallback((key, value) => {
    onChange({ ...options, [key]: value });
  }, [options, onChange]);

  const handleDotColor      = useCallback((v) => update('dotColor',      v), [update]);
  const handleBgColor       = useCallback((v) => update('bgColor',       v), [update]);
  const handleGradientColor = useCallback((v) => update('gradientColor', v), [update]);
  const handleDotStyle      = useCallback((v) => update('dotStyle',      v), [update]);
  const handleEyeStyle      = useCallback((v) => update('eyeStyle',      v), [update]);
  const toggleGradient      = useCallback(() => update('useGradient', !options.useGradient), [update, options.useGradient]);
  const handleSize          = useCallback((e) => update('size',   parseInt(e.target.value)), [update]);
  const handleMargin        = useCallback((e) => update('margin', parseInt(e.target.value)), [update]);
  const handleErrorCorrection = useCallback((v) => update('errorCorrection', v), [update]);
  const handleReset         = useCallback(() => { onChange(defaultCustomizerOptions); setActivePreset(null); }, [onChange]);

  const applyPreset = useCallback((preset) => {
    setActivePreset(preset.id);
    onChange({
      ...options,
      dotColor:      preset.dot,
      bgColor:       preset.bg,
      useGradient:   preset.gradient,
      gradientColor: preset.gc,
      dotStyle:      preset.ds,
      eyeStyle:      preset.es,
    });
  }, [options, onChange]);

  const handleLogoUpload = useCallback((e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      setLogoPreview(ev.target.result);
      update('logo', ev.target.result);
    };
    reader.readAsDataURL(file);
  }, [update]);

  const removeLogo = useCallback(() => {
    setLogoPreview(null);
    update('logo', null);
  }, [update]);

  return (
    <motion.div {...customizerAnim} className="space-y-6">

      {/* Style Presets */}
      <Section title="Quick Presets">
        <div className="grid grid-cols-4 gap-2">
          {PRESETS.map((p) => (
            <PresetCard key={p.id} preset={p} isActive={activePreset === p.id} onClick={applyPreset} />
          ))}
        </div>
      </Section>

      {/* Colors */}
      <Section title="Colors">
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <ColorPicker label="Dot Color"  color={options.dotColor} onChange={handleDotColor} />
          <ColorPicker label="Background" color={options.bgColor}  onChange={handleBgColor}  />
        </div>

        <div className="flex items-center justify-between bg-gray-50 dark:bg-[#0f0f1a] rounded-xl px-4 py-3 border border-gray-200 dark:border-purple-500/10">
          <div>
            <p className="text-sm font-medium text-gray-700 dark:text-gray-300">Gradient Dots</p>
            <p className="text-xs text-gray-400 dark:text-gray-600">Two-color gradient on QR dots</p>
          </div>
          <Toggle checked={options.useGradient} onChange={toggleGradient} />
        </div>

        <AnimatePresence>
          {options.useGradient && (
            <motion.div {...gradientAnim} className="overflow-hidden">
              <ColorPicker label="Gradient End Color" color={options.gradientColor} onChange={handleGradientColor} />
            </motion.div>
          )}
        </AnimatePresence>
      </Section>

      {/* Dot Style */}
      <Section title="Dot Style">
        <div className="grid grid-cols-4 gap-2">
          <StyleOption value="square"  current={options.dotStyle} onClick={handleDotStyle} label="Square">  <DotSquare  /></StyleOption>
          <StyleOption value="rounded" current={options.dotStyle} onClick={handleDotStyle} label="Rounded"> <DotRounded /></StyleOption>
          <StyleOption value="circle"  current={options.dotStyle} onClick={handleDotStyle} label="Circle">  <DotCircle  /></StyleOption>
          <StyleOption value="diamond" current={options.dotStyle} onClick={handleDotStyle} label="Diamond"> <DotDiamond /></StyleOption>
        </div>
      </Section>

      {/* Eye Style */}
      <Section title="Eye Style">
        <div className="grid grid-cols-4 gap-2">
          <StyleOption value="square"  current={options.eyeStyle} onClick={handleEyeStyle} label="Square">  <EyeSquare  /></StyleOption>
          <StyleOption value="rounded" current={options.eyeStyle} onClick={handleEyeStyle} label="Rounded"> <EyeRounded /></StyleOption>
          <StyleOption value="circle"  current={options.eyeStyle} onClick={handleEyeStyle} label="Circle">  <EyeCircle  /></StyleOption>
          <StyleOption value="leaf"    current={options.eyeStyle} onClick={handleEyeStyle} label="Leaf">    <EyeLeaf    /></StyleOption>
        </div>
      </Section>

      {/* Error Correction */}
      <Section title="Error Correction">
        <div className="grid grid-cols-4 gap-2">
          {EC_LEVELS.map((ec) => (
            <button
              key={ec.value}
              type="button"
              onClick={() => handleErrorCorrection(ec.value)}
              className={
                "flex flex-col items-center gap-1 p-2.5 rounded-xl border-2 transition-colors duration-200 " +
                (options.errorCorrection === ec.value
                  ? "border-purple-500 bg-purple-50 dark:bg-purple-900/20"
                  : "border-gray-200 dark:border-gray-700 hover:border-purple-400/50 bg-white dark:bg-[#0f0f1a]")
              }
            >
              <span className={"text-sm font-bold " + (options.errorCorrection === ec.value ? "text-purple-600 dark:text-purple-400" : "text-gray-700 dark:text-gray-300")}>{ec.value}</span>
              <span className="text-xs text-gray-400 dark:text-gray-500">{ec.desc}</span>
            </button>
          ))}
        </div>
        <p className="text-xs text-gray-400 dark:text-gray-600 mt-1">
          💡 Use H (High) when adding a logo — it keeps the QR scannable.
        </p>
      </Section>

      {/* Logo */}
      <Section title="Center Logo">
        {logoPreview ? (
          <div className="flex items-center gap-4 bg-gray-50 dark:bg-[#0f0f1a] rounded-xl p-3 border border-gray-200 dark:border-purple-500/10">
            <img src={logoPreview} alt="Logo preview" className="w-12 h-12 rounded-lg object-contain bg-white border border-gray-200" />
            <div className="flex-1 min-w-0">
              <p className="text-sm font-medium text-gray-700 dark:text-gray-300 truncate">Logo uploaded</p>
              <p className="text-xs text-gray-400">Centered on QR code</p>
            </div>
            <button type="button" onClick={removeLogo} className="text-xs text-red-400 hover:text-red-500 px-2 py-1 rounded-lg hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors duration-200">
              Remove
            </button>
          </div>
        ) : (
          <label className="flex flex-col items-center gap-2 p-4 rounded-xl border-2 border-dashed border-gray-200 dark:border-purple-500/20 hover:border-purple-400/50 cursor-pointer transition-colors duration-200 bg-gray-50 dark:bg-[#0f0f1a]">
            <span className="text-2xl">🖼️</span>
            <span className="text-xs text-gray-500 dark:text-gray-400 text-center">
              Click to upload a logo (PNG, SVG recommended)
            </span>
            <input type="file" accept="image/*" className="hidden" onChange={handleLogoUpload} />
          </label>
        )}
      </Section>

      {/* Size */}
      <Section title="Size">
        <div className="space-y-2">
          <div className="flex items-center justify-between">
            <span className="text-xs text-gray-500 dark:text-gray-400">QR Code Size</span>
            <span className="text-xs font-semibold text-purple-600 dark:text-purple-400 tabular-nums">{options.size}px</span>
          </div>
          <input type="range" min="128" max="512" step="32" value={options.size} onChange={handleSize}
            className="w-full h-2 bg-gray-200 dark:bg-gray-700 rounded-full appearance-none cursor-pointer accent-purple-600" />
          <div className="flex justify-between text-xs text-gray-400">
            <span>128px</span><span>512px</span>
          </div>
        </div>
      </Section>

      {/* Margin */}
      <Section title="Quiet Zone">
        <div className="space-y-2">
          <div className="flex items-center justify-between">
            <span className="text-xs text-gray-500 dark:text-gray-400">Margin around QR</span>
            <span className="text-xs font-semibold text-purple-600 dark:text-purple-400 tabular-nums">{options.margin}</span>
          </div>
          <input type="range" min="0" max="6" step="1" value={options.margin} onChange={handleMargin}
            className="w-full h-2 bg-gray-200 dark:bg-gray-700 rounded-full appearance-none cursor-pointer accent-purple-600" />
          <div className="flex justify-between text-xs text-gray-400">
            <span>None</span><span>Large</span>
          </div>
        </div>
      </Section>

      {/* Reset */}
      <button
        type="button"
        onClick={handleReset}
        className="w-full py-2.5 rounded-xl border border-gray-200 dark:border-purple-500/20 text-sm font-medium text-gray-500 dark:text-gray-400 hover:text-purple-600 dark:hover:text-purple-400 hover:border-purple-400/40 transition-colors duration-200"
      >
        ↺ Reset to Defaults
      </button>

    </motion.div>
  );
});

QrCustomizer.displayName = 'QrCustomizer';
export default QrCustomizer;