// src/QrTypes.js

import React, { useState, useCallback, memo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

// ── Static configs ────────────────────────────────────────────────────────────
const wrapperAnim = { initial: { opacity: 0, y: 12 }, animate: { opacity: 1, y: 0 }, transition: { duration: 0.25 } };
const formAnim    = { initial: { opacity: 0, y: 8  }, animate: { opacity: 1, y: 0 }, exit: { opacity: 0, y: -8 }, transition: { duration: 0.15 } };

export const QR_TYPES = [
  { id: 'url',      label: 'URL',      emoji: '🔗', desc: 'Website link'        },
  { id: 'wifi',     label: 'WiFi',     emoji: '📶', desc: 'Network credentials' },
  { id: 'vcard',    label: 'Contact',  emoji: '👤', desc: 'vCard / contact info' },
  { id: 'sms',      label: 'SMS',      emoji: '💬', desc: 'Pre-filled text'     },
  { id: 'email',    label: 'Email',    emoji: '📧', desc: 'Email template'      },
  { id: 'crypto',   label: 'Crypto',   emoji: '₿',  desc: 'Wallet address'      },
  { id: 'calendar', label: 'Event',    emoji: '📅', desc: 'Calendar event'      },
  { id: 'location', label: 'Location', emoji: '📍', desc: 'GPS coordinates'     },
  { id: 'phone',    label: 'Phone',    emoji: '📞', desc: 'Phone number'        },
  { id: 'text',     label: 'Text',     emoji: '📝', desc: 'Plain message'       },
];

// ── Shared input classes ──────────────────────────────────────────────────────
const inputClass  = "w-full px-4 py-2.5 rounded-xl border-2 border-gray-200 dark:border-purple-500/20 bg-gray-50 dark:bg-[#0f0f1a] text-gray-900 dark:text-white placeholder-gray-400 dark:placeholder-gray-600 text-sm outline-none focus:border-purple-500 transition-colors duration-200";
const selectClass = "w-full px-4 py-2.5 rounded-xl border-2 border-gray-200 dark:border-purple-500/20 bg-gray-50 dark:bg-[#0f0f1a] text-gray-900 dark:text-white text-sm outline-none focus:border-purple-500 transition-colors duration-200 cursor-pointer";

// ── QR string builder ─────────────────────────────────────────────────────────
export const buildQrString = (typeId, fields) => {
  switch (typeId) {
    case 'url':      return fields.url || '';
    case 'wifi':     return "WIFI:T:" + (fields.encryption || 'WPA') + ";S:" + (fields.ssid || '') + ";P:" + (fields.password || '') + ";H:" + (fields.hidden ? 'true' : 'false') + ";;";
    case 'vcard':    return "BEGIN:VCARD\nVERSION:3.0\nFN:" + (fields.fullName || '') + "\nORG:" + (fields.org || '') + "\nTEL:" + (fields.phone || '') + "\nEMAIL:" + (fields.email || '') + "\nURL:" + (fields.website || '') + "\nADR:;;" + (fields.address || '') + ";;;;\nEND:VCARD";
    case 'sms':      return "SMSTO:" + (fields.phone || '') + ":" + (fields.message || '');
    case 'email':    return "mailto:" + (fields.email || '') + "?subject=" + encodeURIComponent(fields.subject || '') + "&body=" + encodeURIComponent(fields.body || '');
    case 'crypto':   return (fields.coin || 'bitcoin') + ":" + (fields.address || '') + (fields.amount ? "?amount=" + fields.amount : '');
    case 'calendar': {
      const fmt = (d) => d ? d.replace(/-/g, '') + 'T000000Z' : '';
      return "BEGIN:VEVENT\nSUMMARY:" + (fields.title || '') + "\nDTSTART:" + fmt(fields.start) + "\nDTEND:" + fmt(fields.end) + "\nLOCATION:" + (fields.location || '') + "\nDESCRIPTION:" + (fields.description || '') + "\nEND:VEVENT";
    }
    case 'location': return "geo:" + (fields.lat || '0') + "," + (fields.lng || '0') + (fields.query ? "?q=" + encodeURIComponent(fields.query) : '');
    case 'phone':    return "tel:" + (fields.phone || '');
    case 'text':     return fields.text || '';
    default:         return '';
  }
};

// ── Field wrapper ─────────────────────────────────────────────────────────────
const Field = memo(({ label, id, required, children }) => (
  <div className="space-y-1.5">
    <label htmlFor={id} className="block text-xs font-semibold text-gray-600 dark:text-gray-400 uppercase tracking-wide">
      {label} {required && <span className="text-purple-500">*</span>}
    </label>
    {children}
  </div>
));
Field.displayName = 'Field';

// ── Form components — all memo'd ──────────────────────────────────────────────
const UrlForm = memo(({ fields, setFields }) => (
  <Field label="Website URL" id="url" required>
    <input id="url" type="url" placeholder="https://example.com" value={fields.url || ''} onChange={(e) => setFields({ ...fields, url: e.target.value })} className={inputClass} />
  </Field>
));

const WifiForm = memo(({ fields, setFields }) => (
  <div className="space-y-4">
    <Field label="Network Name (SSID)" id="ssid" required>
      <input id="ssid" type="text" placeholder="My WiFi Network" value={fields.ssid || ''} onChange={(e) => setFields({ ...fields, ssid: e.target.value })} className={inputClass} />
    </Field>
    <Field label="Password" id="wifi-pass">
      <input id="wifi-pass" type="password" placeholder="Network password" value={fields.password || ''} onChange={(e) => setFields({ ...fields, password: e.target.value })} className={inputClass} />
    </Field>
    <Field label="Encryption" id="encryption">
      <select id="encryption" value={fields.encryption || 'WPA'} onChange={(e) => setFields({ ...fields, encryption: e.target.value })} className={selectClass}>
        <option value="WPA">WPA/WPA2</option>
        <option value="WEP">WEP</option>
        <option value="nopass">None</option>
      </select>
    </Field>
    <div className="flex items-center gap-3">
      <input id="hidden" type="checkbox" checked={fields.hidden || false} onChange={(e) => setFields({ ...fields, hidden: e.target.checked })} className="w-4 h-4 accent-purple-600 cursor-pointer" />
      <label htmlFor="hidden" className="text-sm text-gray-600 dark:text-gray-400 cursor-pointer">Hidden network</label>
    </div>
  </div>
));

const VCardForm = memo(({ fields, setFields }) => (
  <div className="space-y-4">
    <Field label="Full Name" id="fullName" required>
      <input id="fullName" type="text" placeholder="John Doe" value={fields.fullName || ''} onChange={(e) => setFields({ ...fields, fullName: e.target.value })} className={inputClass} />
    </Field>
    <div className="grid grid-cols-2 gap-3">
      <Field label="Phone" id="vc-phone">
        <input id="vc-phone" type="tel" placeholder="+1 234 567 8900" value={fields.phone || ''} onChange={(e) => setFields({ ...fields, phone: e.target.value })} className={inputClass} />
      </Field>
      <Field label="Email" id="vc-email">
        <input id="vc-email" type="email" placeholder="john@example.com" value={fields.email || ''} onChange={(e) => setFields({ ...fields, email: e.target.value })} className={inputClass} />
      </Field>
    </div>
    <Field label="Organization" id="org">
      <input id="org" type="text" placeholder="Company name" value={fields.org || ''} onChange={(e) => setFields({ ...fields, org: e.target.value })} className={inputClass} />
    </Field>
    <Field label="Website" id="vc-website">
      <input id="vc-website" type="url" placeholder="https://example.com" value={fields.website || ''} onChange={(e) => setFields({ ...fields, website: e.target.value })} className={inputClass} />
    </Field>
    <Field label="Address" id="vc-address">
      <input id="vc-address" type="text" placeholder="123 Main St, City, Country" value={fields.address || ''} onChange={(e) => setFields({ ...fields, address: e.target.value })} className={inputClass} />
    </Field>
  </div>
));

const SmsForm = memo(({ fields, setFields }) => (
  <div className="space-y-4">
    <Field label="Phone Number" id="sms-phone" required>
      <input id="sms-phone" type="tel" placeholder="+1 234 567 8900" value={fields.phone || ''} onChange={(e) => setFields({ ...fields, phone: e.target.value })} className={inputClass} />
    </Field>
    <Field label="Message" id="sms-msg">
      <textarea id="sms-msg" rows="3" placeholder="Pre-filled message text..." value={fields.message || ''} onChange={(e) => setFields({ ...fields, message: e.target.value })} className={inputClass + " resize-none"} />
    </Field>
  </div>
));

const EmailForm = memo(({ fields, setFields }) => (
  <div className="space-y-4">
    <Field label="To Email" id="to-email" required>
      <input id="to-email" type="email" placeholder="recipient@example.com" value={fields.email || ''} onChange={(e) => setFields({ ...fields, email: e.target.value })} className={inputClass} />
    </Field>
    <Field label="Subject" id="email-subject">
      <input id="email-subject" type="text" placeholder="Email subject" value={fields.subject || ''} onChange={(e) => setFields({ ...fields, subject: e.target.value })} className={inputClass} />
    </Field>
    <Field label="Body" id="email-body">
      <textarea id="email-body" rows="3" placeholder="Email body text..." value={fields.body || ''} onChange={(e) => setFields({ ...fields, body: e.target.value })} className={inputClass + " resize-none"} />
    </Field>
  </div>
));

const CryptoForm = memo(({ fields, setFields }) => (
  <div className="space-y-4">
    <Field label="Cryptocurrency" id="coin">
      <select id="coin" value={fields.coin || 'bitcoin'} onChange={(e) => setFields({ ...fields, coin: e.target.value })} className={selectClass}>
        <option value="bitcoin">Bitcoin (BTC)</option>
        <option value="ethereum">Ethereum (ETH)</option>
        <option value="litecoin">Litecoin (LTC)</option>
        <option value="dogecoin">Dogecoin (DOGE)</option>
        <option value="monero">Monero (XMR)</option>
      </select>
    </Field>
    <Field label="Wallet Address" id="wallet" required>
      <input id="wallet" type="text" placeholder="Paste wallet address..." value={fields.address || ''} onChange={(e) => setFields({ ...fields, address: e.target.value })} className={inputClass} />
    </Field>
    <Field label="Amount (optional)" id="amount">
      <input id="amount" type="number" placeholder="0.001" step="any" value={fields.amount || ''} onChange={(e) => setFields({ ...fields, amount: e.target.value })} className={inputClass} />
    </Field>
  </div>
));

const CalendarForm = memo(({ fields, setFields }) => (
  <div className="space-y-4">
    <Field label="Event Title" id="cal-title" required>
      <input id="cal-title" type="text" placeholder="Team Meeting" value={fields.title || ''} onChange={(e) => setFields({ ...fields, title: e.target.value })} className={inputClass} />
    </Field>
    <div className="grid grid-cols-2 gap-3">
      <Field label="Start Date" id="start-date" required>
        <input id="start-date" type="date" value={fields.start || ''} onChange={(e) => setFields({ ...fields, start: e.target.value })} className={inputClass} />
      </Field>
      <Field label="End Date" id="end-date">
        <input id="end-date" type="date" value={fields.end || ''} onChange={(e) => setFields({ ...fields, end: e.target.value })} className={inputClass} />
      </Field>
    </div>
    <Field label="Location" id="cal-location">
      <input id="cal-location" type="text" placeholder="Conference Room A" value={fields.location || ''} onChange={(e) => setFields({ ...fields, location: e.target.value })} className={inputClass} />
    </Field>
    <Field label="Description" id="cal-desc">
      <textarea id="cal-desc" rows="2" placeholder="Event details..." value={fields.description || ''} onChange={(e) => setFields({ ...fields, description: e.target.value })} className={inputClass + " resize-none"} />
    </Field>
  </div>
));

const LocationForm = memo(({ fields, setFields }) => (
  <div className="space-y-4">
    <Field label="Search Query (optional)" id="geo-query">
      <input id="geo-query" type="text" placeholder="Eiffel Tower, Paris" value={fields.query || ''} onChange={(e) => setFields({ ...fields, query: e.target.value })} className={inputClass} />
    </Field>
    <div className="grid grid-cols-2 gap-3">
      <Field label="Latitude" id="lat" required>
        <input id="lat" type="number" step="any" placeholder="48.8584" value={fields.lat || ''} onChange={(e) => setFields({ ...fields, lat: e.target.value })} className={inputClass} />
      </Field>
      <Field label="Longitude" id="lng" required>
        <input id="lng" type="number" step="any" placeholder="2.2945" value={fields.lng || ''} onChange={(e) => setFields({ ...fields, lng: e.target.value })} className={inputClass} />
      </Field>
    </div>
  </div>
));

const PhoneForm = memo(({ fields, setFields }) => (
  <Field label="Phone Number" id="tel" required>
    <input id="tel" type="tel" placeholder="+1 234 567 8900" value={fields.phone || ''} onChange={(e) => setFields({ ...fields, phone: e.target.value })} className={inputClass} />
  </Field>
));

const TextForm = memo(({ fields, setFields }) => (
  <Field label="Message" id="plain-text" required>
    <textarea id="plain-text" rows="5" placeholder="Enter any text or message..." value={fields.text || ''} onChange={(e) => setFields({ ...fields, text: e.target.value })} className={inputClass + " resize-none"} />
  </Field>
));

// Add display names
UrlForm.displayName      = 'UrlForm';
WifiForm.displayName     = 'WifiForm';
VCardForm.displayName    = 'VCardForm';
SmsForm.displayName      = 'SmsForm';
EmailForm.displayName    = 'EmailForm';
CryptoForm.displayName   = 'CryptoForm';
CalendarForm.displayName = 'CalendarForm';
LocationForm.displayName = 'LocationForm';
PhoneForm.displayName    = 'PhoneForm';
TextForm.displayName     = 'TextForm';

// ── Form map ──────────────────────────────────────────────────────────────────
const FORM_MAP = {
  url: UrlForm, wifi: WifiForm, vcard: VCardForm, sms: SmsForm,
  email: EmailForm, crypto: CryptoForm, calendar: CalendarForm,
  location: LocationForm, phone: PhoneForm, text: TextForm,
};

// ── Type button ───────────────────────────────────────────────────────────────
const TypeButton = memo(({ type, isActive, onClick }) => (
  <button
    type="button"
    onClick={() => onClick(type.id)}
    title={type.desc}
    className={
      "flex flex-col items-center gap-1 p-2 rounded-xl border-2 transition-colors duration-200 " +
      (isActive
        ? "border-purple-500 bg-purple-50 dark:bg-purple-900/20"
        : "border-gray-200 dark:border-gray-700 hover:border-purple-400/50 bg-white dark:bg-[#0f0f1a]")
    }
  >
    <span className="text-lg">{type.emoji}</span>
    <span className={"text-xs font-medium " + (isActive ? "text-purple-600 dark:text-purple-400" : "text-gray-500 dark:text-gray-500")}>
      {type.label}
    </span>
  </button>
));
TypeButton.displayName = 'TypeButton';

// ── Main component ────────────────────────────────────────────────────────────
const QrTypes = memo(({ onGenerate }) => {
  const [activeType, setActiveType] = useState('url');
  const [fields,     setFields]     = useState({});

  const handleTypeChange = useCallback((typeId) => {
    setActiveType(typeId);
    setFields({});
  }, []);

  const handleGenerate = useCallback(() => {
    const qrString = buildQrString(activeType, fields);
    if (qrString) onGenerate(qrString, activeType);
  }, [activeType, fields, onGenerate]);

  const ActiveForm    = FORM_MAP[activeType];
  const activeTypeDef = QR_TYPES.find((t) => t.id === activeType);

  return (
    <motion.div {...wrapperAnim} className="space-y-5">

      {/* Type grid */}
      <div className="grid grid-cols-5 gap-2">
        <TypeButton type={QR_TYPES[0]} isActive={activeType === QR_TYPES[0].id} onClick={handleTypeChange} />
        <TypeButton type={QR_TYPES[1]} isActive={activeType === QR_TYPES[1].id} onClick={handleTypeChange} />
        <TypeButton type={QR_TYPES[2]} isActive={activeType === QR_TYPES[2].id} onClick={handleTypeChange} />
        <TypeButton type={QR_TYPES[3]} isActive={activeType === QR_TYPES[3].id} onClick={handleTypeChange} />
        <TypeButton type={QR_TYPES[4]} isActive={activeType === QR_TYPES[4].id} onClick={handleTypeChange} />
        <TypeButton type={QR_TYPES[5]} isActive={activeType === QR_TYPES[5].id} onClick={handleTypeChange} />
        <TypeButton type={QR_TYPES[6]} isActive={activeType === QR_TYPES[6].id} onClick={handleTypeChange} />
        <TypeButton type={QR_TYPES[7]} isActive={activeType === QR_TYPES[7].id} onClick={handleTypeChange} />
        <TypeButton type={QR_TYPES[8]} isActive={activeType === QR_TYPES[8].id} onClick={handleTypeChange} />
        <TypeButton type={QR_TYPES[9]} isActive={activeType === QR_TYPES[9].id} onClick={handleTypeChange} />
      </div>

      {/* Form */}
      <AnimatePresence mode="wait">
        <motion.div
          key={activeType}
          {...formAnim}
          className="bg-gray-50 dark:bg-[#0f0f1a] rounded-2xl p-5 border border-gray-200 dark:border-purple-500/10 space-y-4"
        >
          <div className="flex items-center gap-2 pb-3 border-b border-gray-200 dark:border-purple-500/10">
            <span className="text-xl">{activeTypeDef.emoji}</span>
            <div>
              <p className="text-sm font-bold text-gray-800 dark:text-white">{activeTypeDef.label} QR Code</p>
              <p className="text-xs text-gray-400 dark:text-gray-500">{activeTypeDef.desc}</p>
            </div>
          </div>

          <ActiveForm fields={fields} setFields={setFields} />

          <button
            type="button"
            onClick={handleGenerate}
            className="w-full py-3 rounded-xl bg-purple-600 hover:bg-purple-700 text-white font-semibold text-sm transition-colors duration-200 mt-2"
          >
            ✦ Generate {activeTypeDef.label} QR Code
          </button>
        </motion.div>
      </AnimatePresence>

    </motion.div>
  );
});

QrTypes.displayName = 'QrTypes';
export default QrTypes;